/**
 * SQL Query Validator - enforces security policies before any query execution
 */
class QueryValidator(allowedDatabases: Set[String], allowedTables: Set[String]) {

  private val logger = LoggerFactory.getLogger(getClass)

  // Dangerous SQL patterns that must never be executed
  private val forbiddenPatterns = List(
    "(?i)\\bDROP\\b",
    "(?i)\\bDELETE\\b",
    "(?i)\\bINSERT\\b",
    "(?i)\\bUPDATE\\b",
    "(?i)\\bALTER\\b",
    "(?i)\\bCREATE\\b",
    "(?i)\\bTRUNCATE\\b",
    "(?i)\\bGRANT\\b",
    "(?i)\\bREVOKE\\b",
    "(?i)\\bEXEC\\b",
    "(?i)\\bEXECUTE\\b",
    "(?i)\\bMERGE\\b",
    "(?i)\\bCALL\\b",
    "(?i)\\bSET\\b",
    "(?i)\\bUNCACHE\\b",
    "(?i)\\bREFRESH\\b",
    "(?i)\\bADD\\s+JAR\\b",
    "(?i)\\bADD\\s+FILE\\b",
    "(?i)\\bLOAD\\b",
    "(?i)\\bINTO\\b",
    "(?i)\\bOVERWRITE\\b",
    "(?i)--",                    // SQL comments used for injection
    "/\\*",                      // Block comments
    "(?i)\\bUNION\\b.*(?i)\\bSELECT\\b.*(?i)\\bFROM\\b.*(?i)\\binformation_schema\\b",
    ";",                         // Statement chaining
    "(?i)\\bSHOW\\s+DATABASES\\b",
    "(?i)\\bSHOW\\s+TABLES\\b",
    "(?i)\\bDESCRIBE\\b",
    "(?i)\\bEXPLAIN\\b"
  ).map(_.r)

  /**
   * Validates a query is read-only SELECT against allowed tables only.
   * Returns Right(sanitizedQuery) or Left(errorMessage).
   */
  def validate(query: String): Either[String, String] = {
    val trimmedQuery = query.trim

    if (trimmedQuery.isEmpty) {
      return Left("Query cannot be empty")
    }

    if (trimmedQuery.length > 5000) {
      return Left("Query exceeds maximum length of 5000 characters")
    }

    // Check forbidden patterns
    for (pattern <- forbiddenPatterns) {
      if (pattern.findFirstIn(trimmedQuery).isDefined) {
        logger.warn(s"Blocked query containing forbidden pattern: ${pattern.toString()}")
        return Left(s"Query contains forbidden operation. Only SELECT queries are allowed.")
      }
    }

    // Must start with SELECT (after trimming whitespace)
    if (!trimmedQuery.matches("(?i)^\\s*SELECT\\b.*")) {
      return Left("Only SELECT queries are permitted")
    }

    // Parse the SQL using Spark's Catalyst parser to extract referenced tables
    val parsedPlan = Try(CatalystSqlParser.parsePlan(trimmedQuery))

    parsedPlan match {
      case Success(plan) =>
        // Ensure the logical plan is a read-only operation
        if (!isReadOnlyPlan(plan)) {
          return Left("Only read-only SELECT queries are permitted")
        }

        // Extract all table references and validate against allowlist
        val referencedTables = extractTableReferences(plan)
        val unauthorizedTables = referencedTables.filterNot { tableName =>
          val parts = tableName.split("\\.")
          parts.length match {
            case 1 => allowedTables.contains(parts(0).toLowerCase)
            case 2 =>
              allowedDatabases.contains(parts(0).toLowerCase) &&
                allowedTables.contains(s"${parts(0).toLowerCase}.${parts(1).toLowerCase}")
            case _ => false
          }
        }

        if (unauthorizedTables.nonEmpty) {
          logger.warn(s"Blocked query referencing unauthorized tables: ${unauthorizedTables.mkString(", ")}")
          Left(s"Access denied to tables: ${unauthorizedTables.mkString(", ")}. Contact admin for access.")
        } else {
          Right(trimmedQuery)
        }

      case Failure(ex) =>
        logger.warn(s"Failed to parse query: ${ex.getMessage}")
        Left(s"Invalid SQL syntax: ${ex.getMessage}")
    }
  }

  private def isReadOnlyPlan(plan: LogicalPlan): Boolean = {
    plan match {
      case _: Command => false  // DDL/DML commands
      case _ =>
        plan.children.forall(isReadOnlyPlan)
    }
  }

  private def extractTableReferences(plan: LogicalPlan): Set[String] = {
    plan.collect {
      case UnresolvedRelation(multipartIdentifier, _, _) =>
        multipartIdentifier.mkString(".")
    }.toSet
  }
}

/**
 * Rate limiter per user to prevent abuse
 */
class RateLimiter(maxQueriesPerMinute: Int) {
  private val userQueryTimestamps = scala.collection.concurrent.TrieMap[String, List[Long]]()

  def allowQuery(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val oneMinuteAgo = now - 60000

    val timestamps = userQueryTimestamps.getOrElse(userId, List.empty)
    val recentTimestamps = timestamps.filter(_ > oneMinuteAgo)

    if (recentTimestamps.size >= maxQueriesPerMinute) {
      false
    } else {
      userQueryTimestamps.update(userId, now :: recentTimestamps)
      true
    }
  }
}

/**
 * Audit logger for all query attempts
 */
class AuditLogger(spark: SparkSession) {
  private val logger = LoggerFactory.getLogger("AUDIT")

  def logQueryAttempt(userId: String, query: String, allowed: Boolean, reason: Option[String] = None): Unit = {
    val timestamp = java.time.Instant.now().toString
    val status = if (allowed) "ALLOWED" else "BLOCKED"
    val reasonStr = reason.map(r => s" | Reason: $r").getOrElse("")
    logger.info(s"[$timestamp] User: $userId | Status: $status | Query: ${query.take(500)}$reasonStr")
  }

  def logQueryResult(userId: String, query: String, rowCount: Int, durationMs: Long): Unit = {
    val timestamp = java.time.Instant.now().toString
    logger.info(s"[$timestamp] User: $userId | Rows: $rowCount | Duration: ${durationMs}ms | Query: ${query.take(500)}")
  }

  def logQueryError(userId: String, query: String, error: String): Unit = {
    val timestamp = java.time.Instant.now().toString
    logger.error(s"[$timestamp] User: $userId | Error: $error | Query: ${query.take(500)}")
  }
}

/**
 * Secure query executor with timeout, row limits, and resource controls
 */
class SecureQueryExecutor(
  spark: SparkSession,
  validator: QueryValidator,
  rateLimiter: RateLimiter,
  auditLogger: AuditLogger,
  maxRows: Int = 10000,
  queryTimeoutSeconds: Int = 120
) {

  private val logger = LoggerFactory.getLogger(getClass)
  private val queryExecutor = Executors.newFixedThreadPool(10)

  def executeQuery(request: QueryRequest): QueryResponse = {
    val userId = request.userId
    val rawQuery = request.query
    val effectiveMaxRows = request.maxRows.map(_.min(maxRows)).getOrElse(maxRows)

    // Rate limiting
    if (!rateLimiter.allowQuery(userId)) {
      auditLogger.logQueryAttempt(userId, rawQuery, allowed = false, Some("Rate limit exceeded"))
      return QueryResponse(
        success = false,
        data = None,
        error = Some("Rate limit exceeded. Please wait before submitting another query."),
        rowCount = None
      )
    }

    // Validate the query
    validator.validate(rawQuery) match {
      case Left(errorMessage) =>
        auditLogger.logQueryAttempt(userId, rawQuery, allowed = false, Some(errorMessage))
        QueryResponse(
          success = false,
          data = None,
          error = Some(errorMessage),
          rowCount = None
        )

      case Right(validatedQuery) =>
        auditLogger.logQueryAttempt(userId, validatedQuery, allowed = true)
        executeValidatedQuery(userId, validatedQuery, effectiveMaxRows)
    }
  }

  private def executeValidatedQuery(userId: String, query: String, rowLimit: Int): QueryResponse = {
    val startTime = System.currentTimeMillis()

    try {
      val future = queryExecutor.submit(new java.util.concurrent.Callable[QueryResponse] {
        override def call(): QueryResponse = {
          try {
            // Wrap query with LIMIT to prevent unbounded result sets
            val limitedQuery = s"SELECT * FROM ($query) __user_query LIMIT $rowLimit"

            val df = spark.sql(limitedQuery)
            val rows = df.collect()
            val columns = df.columns

            val data = rows.map { row =>
              columns.zipWithIndex.map { case (colName, idx) =>
                val value = row.get(idx)
                val jsValue: JsValue = value match {
                  case null => JsNull
                  case s: String => JsString(s)
                  case n: java.lang.Number => JsNumber(BigDecimal(n.doubleValue()))
                  case b: java.lang.Boolean => JsBoolean(b)
                  case other => JsString(other.toString)
                }
                colName -> jsValue
              }.toMap
            }.toList

            val duration = System.currentTimeMillis() - startTime
            auditLogger.logQueryResult(userId, query, data.size, duration)

            QueryResponse(
              success = true,
              data = Some(data),
              error = None,
              rowCount = Some(data.size)
            )
          } catch {
            case ex: Exception =>
              val duration = System.currentTimeMillis() - startTime
              auditLogger.logQueryError(userId, query, ex.getMessage)
              QueryResponse(
                success = false,
                data = None,
                error = Some(s"Query execution failed: ${ex.getMessage}"),
                rowCount = None
              )
          }
        }
      })

      future.get(queryTimeoutSeconds, TimeUnit.SECONDS)

    } catch {
      case _: TimeoutException =>
        auditLogger.logQueryError(userId, query, "Query timed out")
        QueryResponse(
          success = false,
          data = None,
          error = Some(s"Query timed out after $queryTimeoutSeconds seconds"),
          rowCount = None
        )
      case ex: Exception =>
        auditLogger.logQueryError(userId, query, ex.getMessage)
        QueryResponse(
          success = false,
          data = None,
          error = Some(s"Unexpected error: ${ex.getMessage}"),
          rowCount = None
        )
    }
  }

  def shutdown(): Unit = {
    queryExecutor.shutdown()
  }
}

